func campaignPath(campaign db.Campaign) string {
	return "/app/orgs/" + campaign.OrganizationPublicID + "/campaigns/" + campaign.PublicID
}

func privacySummary(ctx context.Context, settings db.CampaignSettings) string {
	if settings.CollectReferrerDomain || settings.CollectCoarseBrowser || settings.CollectCoarseOS {
		return tr(ctx, "campaign.privacy.balanced_summary")
	}
	return tr(ctx, "campaign.privacy.strict_summary")
}

func chromeSnippet(publicURL string) string {
	return `chrome.runtime.onInstalled.addListener(async (details) => {
  if (details.reason === "install") {
    const token = crypto.randomUUID();
    await chrome.storage.local.set({ koalaByeToken: token });
    chrome.runtime.setUninstallURL(
      "` + publicURL + `?t=" + encodeURIComponent(token)
    );
  }
});`
}

